const base64 = $json.content;
const decoded = Buffer.from(base64, 'base64').toString('utf8');

// convert KEY=VALUE to object
const lines = decoded.split('\n');
const env = {};

for (const line of lines) {
  if (!line || line.startsWith('#')) continue;
  const [key, ...rest] = line.split('=');
  env[key] = rest.join('=');
}

return [{
  raw: decoded,
  parsed: env
}];

// Works for Postman AND real GitHub webhooks
const payload = $input.first().json.body ?? $input.first().json;

const commits = payload.commits || [];
const changedFiles = [];

for (const commit of commits) {
  if (commit.added) changedFiles.push(...commit.added);
  if (commit.modified) changedFiles.push(...commit.modified);
  if (commit.removed) changedFiles.push(...commit.removed);
}

const envFileChanged = changedFiles.includes('.env.staging');

return [{
  json: {
    repository: payload.repository?.full_name,
    branch: payload.ref,
    envFileChanged,
    changedFiles
  }
}];

// 1. Get Base64 content from GitHub node
const base64Content = $input.first().json.content;

// 2. Decode Base64 to text
const decodedText = Buffer.from(base64Content, 'base64').toString('utf-8');

// 3. Split lines and parse KEY=VALUE
const envLines = decodedText.split('\n');

const envObject = {};

for (const line of envLines) {
  const trimmed = line.trim();

  // Ignore empty lines and comments
  if (!trimmed || trimmed.startsWith('#')) continue;

  const [key, ...valueParts] = trimmed.split('=');
  envObject[key] = valueParts.join('=');
}

return [{
  json: {
    rawEnv: decodedText,
    envVars: envObject
  }
}];

// 1. Get Base64 content
const base64Content = $input.first().json.content;

// 2. Decode Base64
const decodedText = Buffer.from(base64Content, 'base64').toString('utf-8');

// 3. Split lines
const lines = decodedText.split('\n');

const gradleVars = {};

for (const line of lines) {
  const trimmed = line.trim();

  // Ignore comments and empty lines
  if (!trimmed || trimmed.startsWith('#')) continue;

  const [key, ...valueParts] = trimmed.split('=');
  gradleVars[key] = valueParts.join('=');
}

return [{
  json: {
    rawGradle: decodedText,
    gradleVars
  }
}];

const inputArray = $input.all().map(item => item.json);

const envVars = inputArray[0]?.envVars || {};
const gradleVars = inputArray[1]?.gradleVars || {};

const changes = [];
const needsCacheInvalidation = [];

for (const key of Object.keys(envVars)) {
  if (!gradleVars.hasOwnProperty(key)) {
    changes.push({
      key,
      envValue: envVars[key],
      gradleValue: null,
      reason: 'missing_in_gradle'
    });
  } else if (envVars[key] !== gradleVars[key]) {
    changes.push({
      key,
      envValue: envVars[key],
      gradleValue: gradleVars[key],
      reason: 'value_changed'
    });
  }

  if (['API_KEY', 'BUILD_VERSION', 'ENVIRONMENT'].includes(key)) {
    needsCacheInvalidation.push(key);
  }
}

return [{
  json: {
    changes,
    hasChanges: changes.length > 0,
    needsCacheInvalidation,
    envVars,
    gradleVars
  }
}];

const data = $input.first().json;
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
const branchName = `config-sync/${timestamp}`;

return [{
  json: {
    ...data,
    branchName
  }
}];

