const base64 = $json.content;
const decoded = Buffer.from(base64, 'base64').toString('utf8');

// convert KEY=VALUE to object
const lines = decoded.split('\n');
const env = {};

for (const line of lines) {
  if (!line || line.startsWith('#')) continue;
  const [key, ...rest] = line.split('=');
  env[key] = rest.join('=');
}

return [{
  raw: decoded,
  parsed: env
}];

const base64 = $json.content;
const decoded = Buffer.from(base64, 'base64').toString('utf8');

// convert KEY=VALUE to object
const lines = decoded.split('\n');
const env = {};

for (const line of lines) {
  if (!line || line.startsWith('#')) continue;
  const [key, ...rest] = line.split('=');
  env[key] = rest.join('=');
}

return [{
  raw: decoded,
  parsed: env
}];

const items = $input.all();

if (items.length !== 3) {
  throw new Error(`Expected 3 inputs, got ${items.length}`);
}

// Env file (source of truth)
const env = items[0].json.parsed;

// build.gradle text (already decoded)
const buildGradleText = items[1].json.raw;

// gradle.properties text (already decoded)
const gradlePropsText = items[2].json.raw;

const updates = {
  buildGradle: {},
  gradleProperties: {}
};

for (const [key, value] of Object.entries(env)) {

  // build.gradle → buildConfigField
  if (buildGradleText.includes(`"${key}"`)) {
    updates.buildGradle[key] = value;
  }

  // gradle.properties → KEY=value
  if (gradlePropsText.includes(`${key}=`)) {
    updates.gradleProperties[key] = value;
  }
}

return [
  {
    json: {
      updates,
      hasChanges:
        Object.keys(updates.buildGradle).length > 0 ||
        Object.keys(updates.gradleProperties).length > 0
    }
  }
];

const updates = $items("Identify Config Changes")[0].json.updates.buildGradle;
let raw = $items("Decode build.gradle")[0].json.raw;

for (const [key, value] of Object.entries(updates)) {
  const regex = new RegExp(
    `(buildConfigField\\s+"String",\\s+"${key}",\\s+"\\\\")(.*?)(")`,
    "g"
  );
  raw = raw.replace(regex, `$1${value}$3`);
}

return [{
  json: {
    path: "app/build.gradle",
    content: Buffer.from(raw).toString("base64"),
    message: "Sync env vars to build.gradle"
  }
}];

const updates = $items("Identify Config Changes")[0].json.updates.gradleProperties;
let raw = $items("Decode gradle.properties")[0].json.raw;

for (const [key, value] of Object.entries(updates)) {
  const regex = new RegExp(`^${key}=.*$`, "gm");
  if (raw.match(regex)) {
    raw = raw.replace(regex, `${key}=${value}`);
  } else {
    raw += `\n${key}=${value}`;
  }
}

return [{
  json: {
    path: "gradle.properties",
    content: Buffer.from(raw).toString("base64"),
    message: "Sync env vars to gradle.properties"
  }
}];

